 {
  "name": "GmailSendEmail",
  "summary": "Send an email to one or multiple recipients, with optional scheduling, cc, and bcc.",
  "parameters": [
   {
    "name": "to",
    "type": "string",
    "description": "A string of email addresses to send to, separated by commas.",
